	seen := make(map[string]bool)
	start := 0

	for i := 0; i < len(s); i++ {
		current := ""
		for j := start; j <= i; j++ {
			current += string(s[j])
			if seen[current] {
				break
			}
		}
		if seen[current] {
			continue
		}
		seen[current] = true
		segments = append(segments, current)
		start = i + 1
	}

	return segments
}
